#!/usr/bin/env bash
# Deploy the /vantaca query form + recommended-action cards to the Slack bot.
#
# WHAT THIS CHANGES (index.mjs, digest.mjs, vantaca-claude.mjs):
#   QUERY FORM (/vantaca, no text): a modal with Manager (optional), a view
#     (All open / Newest / Urgent / Aged 30d+ / Overdue / Water / Parked), and an
#     ASSOCIATION FILTER as a free-text box (name or code) — fuzzy-matched on
#     submit against the cached association list (no flaky typeahead). Submit ->
#     one filtered result set. Association list is pre-warmed at startup.
#   EVERY XN CARD (queue, aged, morning digest) shows a *Recommended:* next action
#     (from the item's priority signals — no extra API/AI call) AND an Advance ▸
#     button (its modal computes the exact next step + editable note on click).
#   Queue views merge vantaca_managerQueue across the selected manager(s), dedupe
#     by XN, filter client-side; the aged view uses vantaca_agedWorkOrders. All
#     cached -> no AI tokens. Free-text still routes to askVantaca. mcpTools()
#     sorts tools by name to keep the prompt cache byte-stable.
#
#   No new Slack scopes — Socket Mode already delivers view_submission + block_actions.
#
# Backs up all four .mjs (timestamped .bak), writes them, node --check each,
# then `systemctl restart vantaca-slack`. Safe to re-run.
#
# REQUIREMENTS (not present in the Claude-Code-on-web sandbox):
#   - ssh client + ~/.ssh/vantaca_vps private key, egress to 134.209.126.217:22
#
cd /root/vantaca-mcp/slack-bot && ts=$(date +%s) && for f in index.mjs vantaca-claude.mjs daily-report.mjs digest.mjs; do { [ -f "$f" ] && cp "$f" "$f.bak.$ts"; } || true; done && printf %s "" | base64 -d > index.mjs && printf %s "" | base64 -d > vantaca-claude.mjs && printf %s "" | base64 -d > daily-report.mjs && printf %s "" | base64 -d > digest.mjs && node --check index.mjs && node --check vantaca-claude.mjs && node --check daily-report.mjs && node --check digest.mjs && echo SYNTAX_OK && systemctl restart vantaca-slack && sleep 2 && echo "slack:$(systemctl is-active vantaca-slack)"
